import { computed, signal } from '@angular/core';
export class UniBaseDatasource {
    constructor() {
        this.selections = signal([]);
        this.sort = signal({
            column: undefined,
            direction: 'indet',
        });
        this.sortColumn = computed(() => this.sort().column);
        this.sortDirection = computed(() => this.sort().direction);
        this.pages = computed(() => Array.from({ length: this.pageCount() }, (_, index) => index + 1));
        this.startIndex = computed(() => {
            const pageSize = this.pageSize();
            const pageIndex = this.pageIndex();
            return pageSize > 0 ? pageIndex * pageSize : 0;
        });
        this.endIndex = computed(() => {
            const pageSize = this.pageSize();
            const total = this.recordCount();
            // If unpaginated (pageSize = 0), return total count
            if (pageSize === 0) {
                return total;
            }
            const start = this.startIndex();
            return Math.min(start + pageSize, total);
        });
        this.disablePrevious = computed(() => {
            const pageSize = this.pageSize();
            return pageSize === 0 ? true : this.pageIndex() === 0;
        });
        this.disableNext = computed(() => {
            const pageSize = this.pageSize();
            return pageSize === 0 ? true : this.pageIndex() + 1 >= this.pageCount();
        });
        this.truncatedPages = computed(() => {
            const currentPage = this.pageIndex() + 1;
            const displayRange = 3;
            const totalPages = this.pageCount();
            const pages = [];
            const startPage = Math.max(1, currentPage - displayRange);
            const endPage = Math.min(totalPages, currentPage + displayRange);
            if (startPage > 1) {
                pages.push(1);
                if (startPage > 2) {
                    pages.push('...');
                }
            }
            for (let i = startPage; i <= endPage; i++) {
                pages.push(i);
            }
            if (endPage < totalPages) {
                if (endPage < totalPages - 1) {
                    pages.push('...');
                }
                pages.push(totalPages);
            }
            return pages;
        });
    }
    isSelected(row) {
        return this.selections().some((selection) => selection === row);
    }
    toggleSelection(row) {
        this.selections.update((selections) => {
            return selections.includes(row) ? selections.filter((i) => i !== row) : [...selections, row];
        });
    }
    clearSelections() {
        this.selections.set([]);
    }
    selectAll() {
        this.selections.set([...this.records()]);
    }
}
